namespace ContosoUniversity.Tests.Helpers;

/// <summary>
/// Provides helper methods for creating in-memory SchoolContext instances for testing.
/// </summary>
public static class TestDbHelper
{
    /// <summary>
    /// Creates a fresh in-memory SchoolContext with a unique database name.
    /// </summary>
    public static SchoolContext CreateContext()
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
            .Options;
        return new SchoolContext(options);
    }

    /// <summary>
    /// Creates an in-memory context seeded with test data for controller testing.
    /// </summary>
    public static SchoolContext CreateSeededContext()
    {
        var context = CreateContext();
        SeedData(context);
        return context;
    }

