    {
        // Arrange - 20 items, 5 per page = 4 total pages, current page is 2
        var list = new PaginatedList<int>(new List<int>(), 20, 2, 5);

        // Assert
        Assert.IsTrue(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_SinglePage_ReturnsFalse()
    {
        // Arrange - 3 items, 5 per page = 1 page, current page is 1
        var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);

        // Assert
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void Create_ReturnsCorrectPageOfItems()
    {
        // Arrange - 10 items, requesting page 2 with page size 3
        var source = Enumerable.Range(1, 10).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 3);

        // Assert
        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages); // ceil(10/3) = 4
        Assert.AreEqual(3, result.Count);
        Assert.AreEqual(4, result[0]); // items 4, 5, 6 on page 2
        Assert.AreEqual(5, result[1]);
        Assert.AreEqual(6, result[2]);
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsFirstItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 10).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 3);

        // Assert
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(3, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(2, result[1]);
        Assert.AreEqual(3, result[2]);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange - 10 items, page 4 with size 3 → only item 10
        var source = Enumerable.Range(1, 10).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 4, 3);

        // Assert
        Assert.AreEqual(4, result.PageIndex);
        Assert.AreEqual(1, result.Count);
        Assert.AreEqual(10, result[0]);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
        Assert.AreEqual(1, result.PageIndex);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }
}

