using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_SetsPageIndex()
    {
        // Arrange & Act
        var list = new PaginatedList<string>(new List<string> { "a", "b" }, 10, 3, 5);

        // Assert
        Assert.AreEqual(3, list.PageIndex);
    }

    [TestMethod]
    [DataRow(10, 5, 2, DisplayName = "10 items / 5 per page = 2 pages")]
    [DataRow(11, 5, 3, DisplayName = "11 items / 5 per page = 3 pages (ceiling)")]
    [DataRow(1, 5, 1, DisplayName = "1 item / 5 per page = 1 page")]
    [DataRow(0, 5, 0, DisplayName = "0 items / 5 per page = 0 pages")]
    [DataRow(5, 5, 1, DisplayName = "5 items / 5 per page = 1 page")]
    [DataRow(100, 10, 10, DisplayName = "100 items / 10 per page = 10 pages")]
    public void Constructor_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedTotalPages)
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

        // Assert
        Assert.AreEqual(expectedTotalPages, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        // Arrange
        var items = new List<string> { "alpha", "beta", "gamma" };

        // Act
        var list = new PaginatedList<string>(items, 20, 1, 3);

        // Assert
        Assert.AreEqual(3, list.Count);
        Assert.AreEqual("alpha", list[0]);
        Assert.AreEqual("beta", list[1]);
        Assert.AreEqual("gamma", list[2]);
    }

    [TestMethod]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int>(), 20, 1, 5);

        // Assert
        Assert.IsFalse(list.HasPreviousPage);
    }

    [TestMethod]
    [DataRow(2, DisplayName = "Page 2")]
    [DataRow(3, DisplayName = "Page 3")]
    [DataRow(10, DisplayName = "Page 10")]
    public void HasPreviousPage_LaterPages_ReturnsTrue(int pageIndex)
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int>(), 100, pageIndex, 5);

        // Assert
        Assert.IsTrue(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        // Arrange - 10 items, 5 per page = 2 total pages, current page is 2
        var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);

        // Assert
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_MiddlePage_ReturnsTrue()
    {
        // Arrange - 20 items, 5 per page = 4 total pages, current page is 2
        var list = new PaginatedList<int>(new List<int>(), 20, 2, 5);

        // Assert
        Assert.IsTrue(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_SinglePage_ReturnsFalse()
    {
        // Arrange - 3 items, 5 per page = 1 page, current page is 1
        var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);

        // Assert
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void Create_ReturnsCorrectPageOfItems()
    {
        // Arrange - 10 items, requesting page 2 with page size 3
        var source = Enumerable.Range(1, 10).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 3);

        // Assert
        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages); // ceil(10/3) = 4
        Assert.AreEqual(3, result.Count);
        Assert.AreEqual(4, result[0]); // items 4, 5, 6 on page 2
        Assert.AreEqual(5, result[1]);
        Assert.AreEqual(6, result[2]);
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsFirstItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 10).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 3);

        // Assert
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(3, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(2, result[1]);
        Assert.AreEqual(3, result[2]);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange - 10 items, page 4 with size 3 → only item 10
        var source = Enumerable.Range(1, 10).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 4, 3);

        // Assert
        Assert.AreEqual(4, result.PageIndex);
        Assert.AreEqual(1, result.Count);
        Assert.AreEqual(10, result[0]);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
        Assert.AreEqual(1, result.PageIndex);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut;

    [TestInitialize]
    public void TestInitialize()
    {
        // Drain static queue to avoid cross-test interference
        var drainer = new NotificationService();
        while (drainer.ReceiveNotification() != null) { }
        drainer.Dispose();

        _sut = new NotificationService();
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _sut?.Dispose();

        // Drain again after test
        var drainer = new NotificationService();
        while (drainer.ReceiveNotification() != null) { }
        drainer.Dispose();
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_MessageContainsDisplayName()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "42", "John Smith", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("John Smith"), $"Message was: {notification.Message}");
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_MessageContainsId()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "42", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("ID: 42"), $"Message was: {notification.Message}");
    }

    [TestMethod]
    public void SendNotification_CreateOperation_MessageContainsCreated()
    {
        // Arrange & Act
        _sut.SendNotification("Course", "1050", "Chemistry", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Course 'Chemistry' has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_UpdateOperation_MessageContainsUpdated()
    {
        // Arrange & Act
        _sut.SendNotification("Course", "1050", "Chemistry", EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteOperation_MessageContainsDeleted()
    {
        // Arrange & Act
        _sut.SendNotification("Course", "1050", "Chemistry", EntityOperation.DELETE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course 'Chemistry' has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_Create_MessageUsesId()
    {
        // Arrange & Act
        _sut.SendNotification("Department", "7", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Department (ID: 7) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_Update_MessageUsesId()
    {
        // Arrange & Act
        _sut.SendNotification("Department", "7", EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Department (ID: 7) has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_Delete_MessageUsesId()
    {
        // Arrange & Act
        _sut.SendNotification("Department", "7", EntityOperation.DELETE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Department (ID: 7) has been deleted", notification.Message);
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_AfterSend_ReturnsNotification()
    {
        // Arrange
        _sut.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "Admin");

        // Act
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
    }

    [TestMethod]
    public void ReceiveNotification_FIFO_Order()
    {
        // Arrange
        _sut.SendNotification("Type1", "1", "First", EntityOperation.CREATE);
        _sut.SendNotification("Type2", "2", "Second", EntityOperation.UPDATE);
        _sut.SendNotification("Type3", "3", "Third", EntityOperation.DELETE);

        // Act & Assert
        var first = _sut.ReceiveNotification();
        Assert.AreEqual("1", first.EntityId);

        var second = _sut.ReceiveNotification();
        Assert.AreEqual("2", second.EntityId);

        var third = _sut.ReceiveNotification();
        Assert.AreEqual("3", third.EntityId);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedByToProvidedUserName()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE, "AdminUser");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("AdminUser", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_NullUserName_DefaultsToSystem()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_NoUserNameParameter_DefaultsToSystem()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_SetsIsReadToFalse()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_SetsEntityType()
    {
        // Arrange & Act
        _sut.SendNotification("Department", "5", "Math", EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("Department", notification.EntityType);
    }

    [TestMethod]
    public void SendNotification_SetsEntityId()
    {
        // Arrange & Act
        _sut.SendNotification("Course", "1050", "Chemistry", EntityOperation.DELETE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("1050", notification.EntityId);
    }

    [TestMethod]
    public void SendNotification_SetsOperationString()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "1", EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("UPDATE", notification.Operation);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAt()
    {
        // Arrange
        var before = DateTime.Now;

        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        var after = DateTime.Now;
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
            $"CreatedAt {notification.CreatedAt} should be between {before} and {after}");
    }

    [TestMethod]
    public void ReceiveNotification_RemovesFromQueue()
    {
        // Arrange
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Act - receive twice
        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(first);
        Assert.IsNull(second);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert - MarkAsRead is a no-op for in-memory implementation
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(999);
        _sut.MarkAsRead(0);
        _sut.MarkAsRead(-1);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert
        var svc = new NotificationService();
        svc.Dispose();
        // Calling dispose again should also not throw
        svc.Dispose();
    }

    [TestMethod]
    public void SendNotification_WithEmptyDisplayName_UsesIdFormat()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "42", "", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithWhitespaceDisplayName_UsesIdFormat()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "42", "   ", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }
}

