+using Microsoft.VisualStudio.TestTools.UnitTesting;
+using System.Collections.Generic;
+using System.Linq;
+
+namespace ContosoUniversity.Tests;
+
+[TestClass]
+public sealed class PaginatedListTests
+{
+    [TestMethod]
+    public void Constructor_SetsPageIndex()
+    {
+        // Arrange & Act
+        var list = new PaginatedList<string>(new List<string> { "a", "b" }, 10, 3, 5);
+
+        // Assert
+        Assert.AreEqual(3, list.PageIndex);
+    }
+
+    [TestMethod]
+    [DataRow(10, 5, 2, DisplayName = "10 items / 5 per page = 2 pages")]
+    [DataRow(11, 5, 3, DisplayName = "11 items / 5 per page = 3 pages (ceiling)")]
+    [DataRow(1, 5, 1, DisplayName = "1 item / 5 per page = 1 page")]
+    [DataRow(0, 5, 0, DisplayName = "0 items / 5 per page = 0 pages")]
+    [DataRow(5, 5, 1, DisplayName = "5 items / 5 per page = 1 page")]
+    [DataRow(100, 10, 10, DisplayName = "100 items / 10 per page = 10 pages")]
+    public void Constructor_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedTotalPages)
+    {
+        // Arrange & Act
+        var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);
+
+        // Assert
+        Assert.AreEqual(expectedTotalPages, list.TotalPages);
+    }
+
+    [TestMethod]
+    public void Constructor_AddsItemsToList()
+    {
+        // Arrange
+        var items = new List<string> { "alpha", "beta", "gamma" };
+
+        // Act
+        var list = new PaginatedList<string>(items, 20, 1, 3);
+
+        // Assert
+        Assert.AreEqual(3, list.Count);
+        Assert.AreEqual("alpha", list[0]);
+        Assert.AreEqual("beta", list[1]);
+        Assert.AreEqual("gamma", list[2]);
+    }
+
+    [TestMethod]
+    public void HasPreviousPage_FirstPage_ReturnsFalse()
+    {
+        // Arrange & Act
+        var list = new PaginatedList<int>(new List<int>(), 20, 1, 5);
+
+        // Assert
+        Assert.IsFalse(list.HasPreviousPage);
+    }
+
+    [TestMethod]
+    [DataRow(2, DisplayName = "Page 2")]
+    [DataRow(3, DisplayName = "Page 3")]
+    [DataRow(10, DisplayName = "Page 10")]
+    public void HasPreviousPage_LaterPages_ReturnsTrue(int pageIndex)
+    {
+        // Arrange & Act
+        var list = new PaginatedList<int>(new List<int>(), 100, pageIndex, 5);
+
+        // Assert
+        Assert.IsTrue(list.HasPreviousPage);
+    }
+
+    [TestMethod]
+    public void HasNextPage_LastPage_ReturnsFalse()
+    {
+        // Arrange - 10 items, 5 per page = 2 total pages, current page is 2
+        var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
+
+        // Assert
+        Assert.IsFalse(list.HasNextPage);
+    }
+
+    [TestMethod]
+    public void HasNextPage_MiddlePage_ReturnsTrue()
+    {
+        // Arrange - 20 items, 5 per page = 4 total pages, current page is 2
+        var list = new PaginatedList<int>(new List<int>(), 20, 2, 5);
+
+        // Assert
+        Assert.IsTrue(list.HasNextPage);
+    }
+
+    [TestMethod]
+    public void HasNextPage_SinglePage_ReturnsFalse()
+    {
+        // Arrange - 3 items, 5 per page = 1 page, current page is 1
+        var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);
+
+        // Assert
+        Assert.IsFalse(list.HasNextPage);
+    }
+
+    [TestMethod]
+    public void Create_ReturnsCorrectPageOfItems()
+    {
+        // Arrange - 10 items, requesting page 2 with page size 3
+        var source = Enumerable.Range(1, 10).AsQueryable();
+
+        // Act
+        var result = PaginatedList<int>.Create(source, 2, 3);
+
+        // Assert
+        Assert.AreEqual(2, result.PageIndex);
+        Assert.AreEqual(4, result.TotalPages); // ceil(10/3) = 4
+        Assert.AreEqual(3, result.Count);
+        Assert.AreEqual(4, result[0]); // items 4, 5, 6 on page 2
+        Assert.AreEqual(5, result[1]);
+        Assert.AreEqual(6, result[2]);
+    }
+
+    [TestMethod]
+    public void Create_FirstPage_ReturnsFirstItems()
+    {
+        // Arrange
+        var source = Enumerable.Range(1, 10).AsQueryable();
+
+        // Act
+        var result = PaginatedList<int>.Create(source, 1, 3);
+
+        // Assert
+        Assert.AreEqual(1, result.PageIndex);
+        Assert.AreEqual(3, result.Count);
+        Assert.AreEqual(1, result[0]);
+        Assert.AreEqual(2, result[1]);
+        Assert.AreEqual(3, result[2]);
+    }
+
+    [TestMethod]
+    public void Create_LastPage_ReturnsRemainingItems()
+    {
+        // Arrange - 10 items, page 4 with size 3 → only item 10
+        var source = Enumerable.Range(1, 10).AsQueryable();
+
+        // Act
+        var result = PaginatedList<int>.Create(source, 4, 3);
+
+        // Assert
+        Assert.AreEqual(4, result.PageIndex);
+        Assert.AreEqual(1, result.Count);
+        Assert.AreEqual(10, result[0]);
+    }
+
+    [TestMethod]
+    public void Create_EmptySource_ReturnsEmptyList()
+    {
+        // Arrange
+        var source = Enumerable.Empty<int>().AsQueryable();
+
+        // Act
+        var result = PaginatedList<int>.Create(source, 1, 5);
+
+        // Assert
+        Assert.AreEqual(0, result.Count);
+        Assert.AreEqual(0, result.TotalPages);
+        Assert.AreEqual(1, result.PageIndex);
+        Assert.IsFalse(result.HasPreviousPage);
+        Assert.IsFalse(result.HasNextPage);
+    }
+}
+

