using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using System;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class DbInitializerTests
{
    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsStudents()
    {
        // Arrange
        var context = TestDbHelper.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(8, context.Students.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsInstructors()
    {
        // Arrange
        var context = TestDbHelper.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(5, context.Instructors.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsDepartments()
    {
        // Arrange
        var context = TestDbHelper.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(4, context.Departments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsCourses()
    {
        // Arrange
        var context = TestDbHelper.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(7, context.Courses.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsEnrollments()
    {
        // Arrange
        var context = TestDbHelper.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(11, context.Enrollments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsOfficeAssignments()
    {
        // Arrange
        var context = TestDbHelper.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(3, context.OfficeAssignments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsCourseAssignments()
    {
        // Arrange
        var context = TestDbHelper.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(8, context.CourseAssignments.Count());
    }

    [TestMethod]
    public void Initialize_AlreadySeeded_DoesNotDuplicateData()
    {
        // Arrange
        var context = TestDbHelper.CreateContext();
        DbInitializer.Initialize(context);
        var initialStudentCount = context.Students.Count();
        var initialCourseCount = context.Courses.Count();

        // Act - call Initialize again
        DbInitializer.Initialize(context);

        // Assert - counts should not change
        Assert.AreEqual(initialStudentCount, context.Students.Count());
        Assert.AreEqual(initialCourseCount, context.Courses.Count());
    }

    [TestMethod]
    public void Initialize_SeedsCorrectStudentData()
    {
        // Arrange
        var context = TestDbHelper.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert - verify specific student data
        var carson = context.Students.FirstOrDefault(s => s.LastName == "Alexander");
        Assert.IsNotNull(carson);
        Assert.AreEqual("Carson", carson.FirstMidName);
        Assert.AreEqual(DateTime.Parse("2010-09-01"), carson.EnrollmentDate);
    }

    [TestMethod]
    public void Initialize_SeedsCorrectInstructorData()
    {
        // Arrange
        var context = TestDbHelper.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        var kim = context.Instructors.FirstOrDefault(i => i.LastName == "Abercrombie");
        Assert.IsNotNull(kim);
        Assert.AreEqual("Kim", kim.FirstMidName);
        Assert.AreEqual(DateTime.Parse("1995-03-11"), kim.HireDate);
    }

    [TestMethod]
    public void Initialize_SeedsCorrectDepartmentData()
    {
        // Arrange
        var context = TestDbHelper.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        var english = context.Departments.FirstOrDefault(d => d.Name == "English");
        Assert.IsNotNull(english);
        Assert.AreEqual(350000m, english.Budget);
    }

    [TestMethod]
    public void Initialize_SeedsCorrectCourseData()
    {
        // Arrange
        var context = TestDbHelper.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        var chemistry = context.Courses.FirstOrDefault(c => c.Title == "Chemistry");
        Assert.IsNotNull(chemistry);
        Assert.AreEqual(1050, chemistry.CourseID);
        Assert.AreEqual(3, chemistry.Credits);
    }

    [TestMethod]
    public void Initialize_SeedsEnrollmentsWithGrades()
    {
        // Arrange
        var context = TestDbHelper.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert - verify some enrollments have grades
        var enrollmentsWithGrades = context.Enrollments.Where(e => e.Grade != null).Count();
        Assert.IsTrue(enrollmentsWithGrades > 0);

        // Verify one without a grade (Anand in Chemistry)
        var enrollmentsWithoutGrades = context.Enrollments.Where(e => e.Grade == null).Count();
        Assert.IsTrue(enrollmentsWithoutGrades > 0);
    }

    [TestMethod]
    public void Initialize_SetsDepartmentAdministrators()
    {
        // Arrange
        var context = TestDbHelper.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert - verify departments have InstructorID set
        var departments = context.Departments.ToList();
        Assert.IsTrue(departments.All(d => d.InstructorID.HasValue));
    }

    [TestMethod]
    public void Initialize_SeedsOfficeAssignmentLocations()
    {
        // Arrange
        var context = TestDbHelper.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        var offices = context.OfficeAssignments.ToList();
        Assert.IsTrue(offices.Any(o => o.Location == "Smith 17"));
        Assert.IsTrue(offices.Any(o => o.Location == "Gowan 27"));
        Assert.IsTrue(offices.Any(o => o.Location == "Thompson 304"));
    }
}

