[TestClass]
public sealed class BaseControllerTests
{
    private SchoolContext _context;
    private TestableBaseController _controller;

    [TestInitialize]
    public void TestInitialize()
    {
        TestDbHelper.DrainNotificationQueue();
        _context = TestDbHelper.CreateContext();
